changeSet.createView:
SELECT /* ── Écriture comptable ───────────────────────────────────── */ cpt.IDCOMPTABILITE, cpt.DATEOPERATION, cpt.DATESERVEUR, cpt.DATEPIECE, cpt.NUMPIECE AS num_piece_comptable, cpt.LIBELLE, cpt.DEBIT, cpt.CREDIT, cpt.ENTREE, cpt.SORTIE,
/* ── Plan comptable ──────────────────────────────────────── */ cpt.planComptable AS num_compte, cpt.CompteAuxi AS compte_auxiliaire, cpt.compteTiers AS compte_tiers, cpt.Compte1 AS compte_contrepartie, cpt.CODE_SENS AS sens,
/* ── Référence de l'opération ────────────────────────────── */ cpt.NUMCREDIT AS ref_credit_comptable, cpt.REFERENCE, cpt.LETTRE AS lettrage, cpt.DATELETTRAGE, cpt.ETAT AS etat_ecriture, cpt.MARQUE AS marque_validation, cpt.CODE_AGENCE AS agence_ecriture, cpt.utilisateur AS agent_saisie,
/* ── Remboursement lié (Reglement) ───────────────────────── */ r.IDREGLEMENT, r.DATE_REGLEMENT, r.NUMPIECE AS num_piece_reglement, r.MONTANT_TOTAL, r.MONTANT_CAPITAL, r.MONTANT_INTERET, r.MONTANT_PENALITE, r.MONTANT_ASSURANCE, r.MONTANT_COMMISSION, r.MONTANT_TAXE, r.MODE_PAIEMENT, r.STATUT AS statut_reglement,
/* ── Crédit concerné ─────────────────────────────────────── */ cr.IDCREDIT, cr.NUMCREDIT AS num_credit, cr.STATUT AS statut_credit, cr.SOLDE_CAPITAL AS solde_capital_credit, cr.DATE_DEBLOCAGE, cr.DATE_ECHEANCE AS date_echeance_credit,
/* ── Ligne de résultat : revenus inclus dans l'écriture ───── */ /* Utilisée pour le rapport des produits (Phase 5 synthèse) */ COALESCE(r.MONTANT_INTERET, 0) + COALESCE(r.MONTANT_COMMISSION, 0) + COALESCE(r.MONTANT_TAXE, 0) AS total_revenus_ecriture
FROM comptabilite cpt
LEFT JOIN Reglement r ON r.idcomptabilite = cpt.IDCOMPTABILITE
LEFT JOIN Credits cr ON cr.IDCREDIT = r.idcredit
